def vpn_login(request):
    """VPN login with MFA"""
    username = request.POST.get('username')
    password = request.POST.get('password')
    mfa_token = request.POST.get('mfa_token')

    duo = DuoMFAHandler()

    # Verify credentials
    auth_ok, msg = duo.authenticate_user(username, password, request.META['REMOTE_ADDR'])
    if not auth_ok:
        return JsonResponse({'error': msg}, status=401)

    # Verify MFA
    if not mfa_token:
        return JsonResponse({'mfa_required': True}, status=403)

    if not duo.verify_hardware_token(username, mfa_token):
        return JsonResponse({'error': 'MFA verification failed'}, status=401)

    # Grant VPN access
    return JsonResponse({'success': True, 'token': 'vpn_session_token'})

import json
from elasticsearch import Elasticsearch
from datetime import datetime, timedelta

class VPNAnomalyDetection:
    """VPN threat detection and monitoring"""

    def __init__(self):
        self.es = Elasticsearch(['localhost:9200'])
        self.threat_threshold = 0.7

    def detect_impossible_travel(self, username):
        """Detect impossible travel velocity"""
        # Get last two logins
        logins = self.es.search(
            index='vpn-logs-*',
            body={
                'query': {'match': {'username': username}},
                'sort': [{'timestamp': {'order': 'desc'}}],
                'size': 2
            }
        )['hits']['hits']

        if len(logins) < 2:
            return False

        # Calculate distance and velocity
        loc1 = logins[0]['_source']['location']
        loc2 = logins[1]['_source']['location']
        time_diff = (
            datetime.fromisoformat(logins[0]['_source']['timestamp']) -
            datetime.fromisoformat(logins[1]['_source']['timestamp'])
        ).total_seconds() / 3600

        # Haversine distance calculation
        distance = self.calc_distance(loc1, loc2)
        velocity = distance / time_diff

        return velocity > 900  # > 900 km/h = impossible

    def detect_mfa_failures(self, username):
        """Detect MFA brute force attempts"""
        failures = self.es.search(
            index='vpn-logs-*',
            body={
                'query': {
                    'bool': {
                        'must': [
                            {'match': {'username': username}},
                            {'term': {'success': False}},
                            {'range': {'timestamp': {'gte': 'now-1h'}}}
                        ]
                    }
                }
            }
        )['hits']['total']['value']

        return failures > 5

    def calc_distance(self, loc1, loc2):
        """Calculate distance between locations"""
        from math import radians, sin, cos, sqrt, atan2

        lat1, lon1 = radians(loc1['lat']), radians(loc1['lon'])
        lat2, lon2 = radians(loc2['lat']), radians(loc2['lon'])

        a = sin((lat2-lat1)/2)**2 + cos(lat1)*cos(lat2)*sin((lon2-lon1)/2)**2
        return 6371 * 2 * atan2(sqrt(a), sqrt(1-a))
